            <div className="space-y-1">
              <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Bố cục kịch bản (Layout)</label>
              <select value={state.scriptLayout} onChange={e => setState(p => ({ ...p, scriptLayout: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none">
                <option value="">-- Random Layout --</option>
                {LAYOUT_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}
              </select>
            </div>

            <div className="space-y-2">
              <label className="block text-[10px] font-black text-slate-500 uppercase px-1 tracking-widest">3. Bối cảnh (Background)</label>
              <div className="grid grid-cols-1 md:grid-cols-12 gap-4">
                <div className="md:col-span-4 space-y-2">
                   <div 
                    onClick={() => backgroundInputRef.current?.click()}
                    className="aspect-square bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl flex items-center justify-center cursor-pointer hover:bg-slate-100 hover:border-orange-400 transition-all overflow-hidden relative group"
                   >
                     {state.backgroundPreviewUrl ? (
                        <img src={state.backgroundPreviewUrl} className="w-full h-full object-cover" />
                     ) : (
                        <div className="text-center p-2">
                           <svg className="w-6 h-6 text-slate-300 mx-auto mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                           <span className="text-[8px] font-black text-slate-400 uppercase">Ảnh bối cảnh</span>
                        </div>
                     )}
                     <input type="file" ref={backgroundInputRef} onChange={handleBackgroundFileChange} className="hidden" accept="image/*" />
                   </div>
                </div>
                <div className="md:col-span-8">
                  <textarea
                    value={state.scriptNote}
                    onChange={e => setState(p => ({ ...p, scriptNote: e.target.value }))}
                    placeholder="Mô tả bối cảnh chi tiết bằng chữ (VD: phòng khách sang trọng, quán cafe ngoài trời...). Ghi chú này CHỈ dùng cho tạo ảnh, KHÔNG xuất hiện trong kịch bản chữ."
                    className="w-full p-4 border border-slate-200 rounded-2xl h-full min-h-[120px] text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all resize-none font-medium leading-relaxed"
