/**
 * Tạo kịch bản TikTok với NGUYÊN TẮC CỘNG ĐỒNG nghiêm ngặt.
 */
export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  sceneCount: number
): Promise<ScriptParts> => {
  const ai = getAiClient();

  const FORBIDDEN_TERMS = `
    Facebook, Shopee, Lazada, Tiki, Zalo, QR, Chuyển khoản, Fanpage, Địa Chỉ, Số điện thoại, Nước Anh, Nước Pháp, Trung Quốc, Tên quốc gia, Dior, Gucci, Adidas, Nike, giá rẻ, chốt, So sánh với các thương hiệu khác, Làm dày, Chống rụng, Kích thích mọc tóc, Làm hồng, Se Khít, Da đen, Đồ điên, Con thiểu năng, Sale sốc, Mua ngay đi, Cam kết khẳng định, So sánh nhất, Top 1, Hàng đầu, Chính hãng, Độc quyền, Duy nhất, 100%, Tuyệt đối, Chắc chắn, Giá rẻ nhất, Giá tốt nhất, Cam kết, Tốt nhất, Tức thì, Chất lượng nhất, Top 1 thế giới, Vĩnh viễn, Hoàn toàn, Cam kết hiệu quả, Bảo hành trọn đời, Xả hàng, Từ ngữ liên quan điều trị, Y tế, Trị + ..., Điều trị, Dứt điểm, Chữa khỏi, Đánh bay, Hiệu quả, Loại bỏ, Phục hồi, Xóa bỏ, Giảm mỡ, Kem tan mỡ, Giảm kích thước các vòng, Làm săn chắc, Ngăn ngừa, Làm chậm tốc độ, Dừng mọc lông, Bảo vệ da khỏi, Cam kết giao hàng, Khuyến mãi ảo, Công dụng quá đà, Gửi hàng 2 ngày nhận được, Nhận hàng không ưng trả lại, Bỏ qua sẽ hối hận cả đời, Tặng miễn phí sản phẩm, Chia sẻ để mua hàng giá 0đ, Quà tặng miễn phí cho tất cả mọi người, Nhanh tay mua ngay để được giá ưu đãi tốt nhất, Ấn vào Link để nhận thưởng miễn phí, Diệt mụn, Phòng chống nhiễm trùng, Ngăn chặn lão hóa, Làm đảo ngược tình trạng lão hóa, Giảm cân / Tăng cân, Tăng cường cảm xúc, Hấp dẫn giới tính, Ưu đãi huỷ diệt, Khuyến Mãi cực sốc, Giảm giá kịch sàn, Thanh lý toàn bộ, Nhanh tay đặt hàng, Có 1 không 2.
  `;

  let dialectInstruction = voice === 'Miền Bắc' 
    ? `VĂN PHONG MIỀN BẮC (HÀ NỘI): dùng nhé, ạ, thế, đấy, chứ.` 
    : `VĂN PHONG MIỀN NAM (SÀI GÒN): dùng nha, nè, nghen, thiệt, hông, vầy.`;

  const prompt = `
    Tạo kịch bản TikTok cho "${productName}". USP: "${keyword}". Layout: "${scriptLayout}". Giới tính: ${gender}.
    YÊU CẦU: Đúng ${sceneCount} phần (v1..v${sceneCount}). KHÔNG nhắc bối cảnh/địa điểm.
    ${dialectInstruction} Trên 160 và dưới 180 ký tự/phần.

    !!! CẢNH BÁO VI PHẠM CỘNG ĐỒNG - TUYỆT ĐỐI KHÔNG SỬ DỤNG CÁC TỪ SAU !!!:
    ${FORBIDDEN_TERMS}
  `;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.OBJECT, properties, required }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) {
    const fallback: ScriptParts = {};
    for (let i = 1; i <= sceneCount; i++) fallback[`v${i}`] = '';
    return fallback;
  }
};

/**
 * Tạo hình ảnh với TUÂN THỦ TUYỆT ĐỐI GHI CHÚ NHÂN VẬT & SẢN PHẨM.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "",
  visualNote: string = "",
  occupancyPercent: number = 20,
  backgroundImagePart: any | null = null
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const baseStyle = is3D 
    ? "High-quality 3D Animation Pixar/Disney style, vibrant colors, expressive character design, polished CGI, masterpiece."
    : "Photorealistic RAW PHOTO, 8k resolution, authentic skin textures, cinematic lighting.";

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  // Logic chia 100 ô theo yêu cầu người dùng
  const gridLogic = `
    CRITICAL PROPORTION CALCULATION (MANDATORY):
    The output image is 1080x1920. 
    Mathematically divide this frame into a grid of 10x10 (total 100 equal cells). 
    Each cell represents 1% of the frame area.
    The product "${productName}" MUST occupy exactly ${occupancyPercent} cells of this grid to represent ${occupancyPercent}% of the total frame area.
    Position the product clearly within the frame respecting this precise mathematical scale ratio.
  `;

  const visualRules = `
    CRITICAL VISUAL RULES (STRICT NO-TEXT POLICY):
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS.
    2. The background must be CLEAN and FREE of signage, posters, labels, or written words.
    3. If the context implies a screen or sign, leave it BLANK or Abstract.
    4. NO UI elements, NO speech bubbles, NO watermarks, NO subtitles.
    5. The image must be purely visual storytelling.
    6. ABSOLUTELY NO ICONS, NO GRAPHICS, NO EMOJIS, NO VISUAL EFFECTS, NO OVERLAYS.
    7. Do NOT simulate TikTok UI or video editing effects. It must look like a RAW PHOTO.

    CRITICAL RESTRICTIONS & RULES: 
    1. NO CHILDREN, NO KIDS, NO BABIES. The subject must be an adult.
    2. ${is3D ? "Must look like high-quality 3D CGI." : "Must look like a real photo."}
    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT/DEVICE IN THIS IMAGE.' : `
    3. STRICT PRODUCT FIDELITY (MANDATORY - TUYỆT ĐỐI):
       - The product "${productName}" MUST MATCH the input reference image 1:1.
       - PRESERVE PATTERNS & TEXTURES: Any pattern (họa tiết), logo, or design on the product surface must be preserved.
       - PRESERVE DIMENSIONS: Do not resize or distort the product logic.
       - DO NOT change shape, proportions, or physical parts.
       - LOCK the product appearance exactly to the original photo provided.
       - CONSISTENT SCALE: Ensure the product scale is consistent across all generated images based on the ${occupancyPercent}% grid rule.`}
  `;

  const characterFidelityRule = `
    !!! CRITICAL CHARACTER FIDELITY MANDATE (ABSOLUTE PRIORITY) !!!:
    Follow these instructions for appearance, body shape, style, and clothing: "${characterDescription}".
    Gender: Adult Vietnamese ${gender}.
    - MANDATORY: If description mentions body type (e.g., chubby, muscular, slim), clothing style, or fashion vibe, apply it 100%. 
    - This text-based description OVERRIDES any default assumptions from reference images.
  `;

  const identityRule = faceImagePart 
    ? `IDENTITY: Transfer EXACT facial features/hair from FACE_REFERENCE. Body shape and clothing MUST follow the mandate above.`
    : `IDENTITY: Adult Vietnamese ${gender} matching the character description mandate.`;

  const outfitRule = outfitImagePart ? `
    OUTFIT: Use textures from "${outfitDescription}". Priority given to text characterDescription if they conflict. NEVER use the face from the outfit photo.
  ` : "";

  const backgroundRule = backgroundImagePart 
    ? `BACKGROUND: Use the EXACT architectural setting, color palette, and atmosphere from the provided BACKGROUND_REFERENCE image. If text description exists, merge it with the reference image context.`
    : `BACKGROUND: ${backgroundNote || 'lifestyle setting'}.`;

  const sceneInstruction = `SCENE: Context: "${scriptPart}". ${backgroundRule}`;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    ${gridLogic}
    ${characterFidelityRule}
    ${identityRule}
    ${outfitRule}
    ${visualRules}
    ${visualNote ? `VISUAL COMPOSITION: ${visualNote}.` : ""}
    ${sceneInstruction} 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (backgroundImagePart) contents.push({ inlineData: backgroundImagePart });
  if (!isNoProductRequested && referenceImageParts.length > 0) contents.push({ inlineData: referenceImageParts[0] });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

/**
 * Generates a video prompt for VEO-3 model based on script and visual context.
 */
export const generateKocVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceTag = voice === 'Miền Bắc' ? 'Northern Vietnamese' : 'Southern Vietnamese';
  const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

  const productInteractionRule = isNoProductRequested
    ? `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - TUYỆT ĐỐI KHÔNG xuất hiện sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và tương tác. Kịch bản: "${scriptText}".`
    : `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - Nhân vật đang cầm trên tay sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và tương tác. Kịch bản: "${scriptText}".
      - [SẢN PHẨM PHẢI GIỐNG ẢNH THAM CHIẾU 100%, KHÔNG BIẾN DẠNG]`;

  const instructionPrompt = `
  Nhiệm vụ: Viết một lời nhắc (Prompt) chi tiết để tạo video AI (VEO-3) dài 8 giây cho video KOC Review.
  PHONG CÁCH VIDEO: ${is3D ? "3D Animation / CGI Style" : "Photorealistic / Real Life Style"}.

  CẤU TRÚC PROMPT:
  PHẦN 1: NHÂN VẬT & DIỆN MẠO (BẮT BUỘC NHẤT QUÁN). Nhân vật người Việt Nam. ${is3D ? "Phong cách hoạt hình 3D Pixar/Disney." : "Phong cách người thật chân thực."}
  ${productInteractionRule}
  PHẦN 3: BỐI CẢNH & ÁNH SÁNG. Một không gian sống hiện đại, sạch sẽ. ${is3D ? "Môi trường 3D sống động." : "Ánh sáng điện ảnh chân thực."}
  PHẦN 4: CHUYỂN ĐỘNG MÁY ẢNH (9:16). Cách nhân vật di chuyển và tương tác với Camera. Có Dolly In/Dolly Out vào sản phẩm/nhân vật (tuyệt đối không thay đổi bối cảnh/nhân vật).
  PHẦN 5: LỜI THOẠI (DÙNG CHO ĐỒNG BỘ): ✨ Model speaks in ${voiceTag} voice (${voiceGender}): "${scriptText}"
  PHẦN 6: CHẤT LƯỢNG KỸ THUẬT: 4K, ${is3D ? "3D Animation, Masterpiece CGI, 60fps" : "Realistic, Cinematic Lighting, Photorealistic, 60fps"}, Không có nhạc nền.

  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất (trừ phần lời thoại). Không xuống dòng.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) {
    contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  }
  if (generatedImageBase64) {
    contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    console.error("Video prompt generation error", error);
    return "Error generating video prompt.";
  }
};

